// Decode base64 content from GitHub API
const raw  = $input.first().json.content;
const sha  = $input.first().json.sha;
const text = Buffer.from(raw, 'base64').toString('utf-8');

// Parse links (skip comments and empty lines)
const links = text.split('\n')
  .map(l => l.trim())
  .filter(l => l && !l.startsWith('#') && l.includes('pin'));

// Take first 3
const toPost = links.slice(0, 3);
const remaining = links.slice(3);

return toPost.map(url => ({
  json: { url, sha, allLinks: links, remaining }
}));

const html = $input.first().json.data || '';
const pinterestUrl = $node['Parse & Pick 3 Links'].json.url;

// Extract image URL
const patterns = [
  /"contentUrl":"(https:\/\/i\.pinimg\.com\/originals\/[^"]+)"/,
  /"url":"(https:\/\/i\.pinimg\.com\/originals\/[^"]+)"/,
  /(https:\/\/i\.pinimg\.com\/originals\/[^"\s]+\.(?:jpg|jpeg|png))/,
  /(https:\/\/i\.pinimg\.com\/736x\/[^"\s]+\.(?:jpg|jpeg|png))/,
];

let mediaUrl = null;
let mediaType = 'image';

// Check video first
const vm = html.match(/"contentUrl":"(https:\/\/v[^"]+\.mp4[^"]*)"/);
if (vm) { mediaUrl = vm[1]; mediaType = 'video'; }

if (!mediaUrl) {
  for (const p of patterns) {
    const m = html.match(p);
    if (m) { mediaUrl = m[1]; break; }
  }
}

// Random caption
const captions = [
  "✨ Beautiful moments captured. 📸\n\n#photography #beautiful #amazing #aesthetic #instagood #viral #trending",
  "🌟 Life is beautiful. Enjoy every moment. 💫\n\n#life #beautiful #moments #photography #instagood #explore",
  "📸 A picture says a thousand words. 🎨\n\n#photography #art #beautiful #creative #aesthetic #photooftheday",
  "💫 Creating memories one photo at a time. ✨\n\n#photography #memories #beautiful #instagood #reels #viral",
  "🌈 Colors of life. 🎨\n\n#colorful #beautiful #photography #aesthetic #instagram #viral #trending",
  "🔥 Absolutely stunning! 😍\n\n#stunning #beautiful #photography #amazing #viral #trending #reels",
  "💎 Pure perfection. ✨\n\n#perfect #beautiful #photography #aesthetic #instagood #amazing",
  "🌸 Beauty is everywhere. 🌺\n\n#beauty #beautiful #nature #photography #aesthetic #instagood",
];
const caption = captions[Math.floor(Math.random() * captions.length)];

return [{ json: {
  ...($node['Parse & Pick 3 Links'].json),
  media_url: mediaUrl,
  media_type: mediaType,
  caption: caption,
}}];

// Remove posted URL from links and update GitHub
const postedUrl   = $node['Parse & Pick 3 Links'].json.url;
const sha         = $node['Parse & Pick 3 Links'].json.sha;
const allLinks    = $node['Parse & Pick 3 Links'].json.allLinks;
const postId      = $input.first().json.id;
const repo        = $env.GITHUB_REPO;
const token       = $env.GITHUB_TOKEN;

// Remove posted link
const remaining = allLinks.filter(l => l !== postedUrl);
const newContent = "# Add your Pinterest links below (one per line)\n# Lines starting with # are ignored\n\n"
  + remaining.join('\n') + '\n';

const encoded = Buffer.from(newContent).toString('base64');

// Update links.txt
await $helpers.httpRequest({
  method: 'PUT',
  url: `https://api.github.com/repos/${repo}/contents/links.txt`,
  headers: {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({
    message: `Auto: Posted ${postedUrl.slice(-20)}`,
    content: encoded,
    sha: sha,
  }),
});

return [{ json: { success: true, post_id: postId, posted_url: postedUrl }}];
